// 1. GET DATA FROM PREVIOUS NODES
// Pobieramy dane z węzła Interpreter Metadata (korzystając z .first() dla trybu Run Once)
const aiData = $('Interpreter Metadata').first().json.output; 
const notionData = $input.first().json; 

// 2. PREPARE TODAY'S DATE
const today = new Date().toISOString().split('T')[0];

// 3. WEIGHT AND HEIGHT (Overwrite, unless AI returned empty/0)
// Używamy uproszczonych nazw propertisów z panelu po lewej
let result = {
  weight: (aiData.weight > 0) ? aiData.weight : (notionData.property_weight_kg || null),
  height: (aiData.height > 0) ? aiData.height : (notionData.property_height_cm || null)
};

// 4. FUNCTION TO CREATE HISTORY (Appending)
function appendHistory(notionPropName, aiValue) {
  // Ponieważ Notion zwraca teraz zwykły tekst (string), wyciągamy go bezpośrednio
  let oldText = notionData[notionPropName] || "";

  // Dodajemy enter, jeśli był stary tekst i nie kończy się enterem
  if (oldText.length > 0 && !oldText.endsWith("\n")) {
    oldText += "\n";
  }

  // If AI found something and it's not "empty"
  if (aiValue && aiValue !== "empty" && aiValue !== "") {
    return oldText + today + ": " + aiValue;
  }

  // If AI found nothing, return the old text
  return oldText.trim();
}

// 5. APPLY THE FUNCTION
result.injuries = appendHistory('property_injuries_and_diseases', aiData.injuries_and_diseases);
result.interests = appendHistory('property_interests_and_disciplines', aiData.interests_and_disciplines);
result.equipment = appendHistory('property_equipment_and_tools', aiData.equipment_and_tools);
result.goal = appendHistory('property_goal', aiData.goal);

// 6. GENERATE SUMMARY FOR TELEGRAM
let summary = "✅ Zaktualizowałem Twój profil!\n\nZanotowałem:\n";

if (aiData.weight > 0) summary += `⚖️ Waga: ${aiData.weight} kg\n`;
if (aiData.height > 0) summary += `📏 Wzrost: ${aiData.height} cm\n`;
if (aiData.goal && aiData.goal !== "empty" && aiData.goal !== "") summary += `🎯 Cel: ${aiData.goal}\n`;
if (aiData.injuries_and_diseases && aiData.injuries_and_diseases !== "empty" && aiData.injuries_and_diseases !== "") summary += `🩹 Zdrowie: ${aiData.injuries_and_diseases}\n`;
if (aiData.interests_and_disciplines && aiData.interests_and_disciplines !== "empty" && aiData.interests_and_disciplines !== "") summary += `⚽ Zainteresowania: ${aiData.interests_and_disciplines}\n`;
if (aiData.equipment_and_tools && aiData.equipment_and_tools !== "empty" && aiData.equipment_and_tools !== "") summary += `🏋️ Sprzęt: ${aiData.equipment_and_tools}`;


result.summary_text = summary;
// 7. OUTPUT THE FINAL DATA PACKAGE
return [{ json: result }];

parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "date": {
      "type": "string",
      "description": "Calculated date in YYYY-MM-DD format. Return empty string '' if the user refers to the last workout."
    },
    "workout_type": {
      "type": "string",
      "enum": [
        "Cardio",
        "Rekreacja",
        "HIIT",
        "Siłowy",
        "Basen",
        "Rower",
        "Rozciąganie",
        "Inne"
      ],
      "description": "Wybierz najbardziej pasującą kategorię. Jeśli żadna nie pasuje, wybierz 'Inne'."
    },
    "status": {
      "type": "string",
      "enum": ["Done", "Rejected", "Todo", "In Progress"]
    },
    "rpe": {
      "type": "number"
    },
    "comment": {
      "type": "string",
      "description": "Comment in Polish: feelings, pain, deviations."
    },
    "training_plan": {
      "type": "string",
      "description": "List of exercises, sets, reps, and weights performed (in Polish). Return '' if not mentioned."
    }
  },
  "required": ["date", "workout_type", "status"]
}

